// CSV парсер
function splitLine(line) {
  const res = []; let cur = '', inQ = false;
  for (let i = 0; i < line.length; i++) {
    const c = line[i];
    if (c === '"') { if (inQ && line[i+1]==='"') { cur+='"'; i++; } else inQ=!inQ; }
    else if (c === ',' && !inQ) { res.push(cur); cur=''; }
    else cur += c;
  }
  res.push(cur); return res;
}
function toNum(s) { return parseFloat(String(s||0).replace(/[\s\u00a0]/g,'').replace(',','.')) || 0; }
function fmtNum(n) {
  if (!n) return '—';
  if (Math.abs(n) < 1e6) return (n/1e3).toLocaleString('ru-RU',{minimumFractionDigits:0,maximumFractionDigits:0}) + ' тыс ₽';
  return (n/1e6).toLocaleString('ru-RU',{minimumFractionDigits:2,maximumFractionDigits:2}) + ' млн ₽';
}

const today = new Date().toLocaleDateString('ru-RU', {day:'2-digit',month:'2-digit',year:'numeric'});

// --- ЕЛС данные (col B=дата, C=Остаток 22%, D=Остаток 0%) ---
const elsText  = $('Fetch ELS CSV').first().json.data || '';
const elsLines = elsText.trim().split(/\r?\n/).filter(l => l.trim());
let els0 = '—', els22 = '—', elsDate = today;
for (let i = elsLines.length - 1; i >= 1; i--) {
  const c = splitLine(elsLines[i]);
  if ((c[2]||'').trim() || (c[3]||'').trim()) {
    const rawDate = (c[1]||'').trim();
    if (rawDate) {
      const dp = rawDate.split('/');
      elsDate = dp.length===3 ? dp[1]+'.'+dp[0]+'.'+dp[2] : rawDate;
    }
    const n22 = toNum(c[2]);
    const n0  = toNum(c[3]);
    els22 = n22 ? fmtNum(n22) : ((c[2]||'').trim() || '—');
    els0  = n0  ? fmtNum(n0)  : ((c[3]||'').trim() || '—');
    break;
  }
}

// --- Задолженность ---
const debtText = $('Fetch Debt CSV').first().json.data || '';
const debtLines = debtText.trim().split(/\r?\n/);
const hdr = splitLine(debtLines[0] || '');
const idxDate   = hdr.indexOf('as_of_date');
const idxClient = hdr.indexOf('client_name');
const idxOver   = hdr.indexOf('overdue_amount');
const idxDays   = hdr.indexOf('days_overdue');
const idxCredit = hdr.indexOf('credit_days_from_registry');

const allDates = debtLines.slice(1).map(l => splitLine(l)[idxDate]).filter(Boolean).sort();
const snap = allDates[allDates.length - 1] || '';

const clientMap = {};
debtLines.slice(1).forEach(line => {
  const cells = splitLine(line);
  if (!cells.length || cells[idxDate] !== snap) return;
  const overAmt = toNum(cells[idxOver]);
  if (overAmt <= 0) return;
  const client = (cells[idxClient] || '').trim();
  if (!client) return;
  if (!clientMap[client]) clientMap[client] = { overdue: 0, maxDays: 0 };
  clientMap[client].overdue += overAmt;
  const actual = Math.max(0, toNum(cells[idxDays]) - toNum(cells[idxCredit]));
  if (actual > clientMap[client].maxDays) clientMap[client].maxDays = actual;
});

const topDebt = Object.entries(clientMap)
  .sort((a,b) => b[1].overdue - a[1].overdue)
  .slice(0, 10)
  .map(([client, info]) => ({ client, fmt: fmtNum(info.overdue) }));

// --- HTML письмо ---
const TH  = 'padding:8px 12px;font-size:11px;font-weight:600;letter-spacing:.05em;color:#fff;white-space:nowrap';
const TD1 = 'padding:8px 12px;border-bottom:1px solid #e5e7eb;font-size:13px;color:#1a2a4a';
const TD2 = 'padding:8px 12px;border-bottom:1px solid #e5e7eb;font-size:13px;font-weight:700;color:#c0152f;text-align:right';

const debtRows = topDebt.map((r,i) => {
  const bg = i%2===0 ? '#fff' : '#f8f9fa';
  return '<tr style="background:'+bg+'"><td style="'+TD1+'">'+r.client+'</td><td style="'+TD2+'">'+r.fmt+'</td></tr>';
}).join('');

const emailHtml = '<!DOCTYPE html><html><body style="margin:0;padding:0;background:#f7f8fa;font-family:Arial,sans-serif">' +
'<table width="620" cellpadding="0" cellspacing="0" border="0" style="margin:24px auto">' +
'<tr><td style="background:#fff;border-radius:12px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,.08)">' +
'<table width="620" cellpadding="0" cellspacing="0" border="0">' +

'<tr><td style="background:#1a2a4a;padding:18px 24px;border-radius:12px 12px 0 0">' +
'<div style="color:#fff;font-size:17px;font-weight:700">Остатки на ЕЛС — ' + elsDate + '</div>' +
'<div style="color:rgba(255,255,255,.7);font-size:12px;margin-top:3px">ООО «ТК ВЕЛЕС» &nbsp;|&nbsp; сформировано ' + today + '</div>' +
'</td></tr>' +

'<tr><td style="padding:16px 24px 8px">' +
'<table width="572" cellpadding="0" cellspacing="0" border="0" style="border-collapse:collapse;border:1px solid #e5e7eb;border-radius:6px">' +
'<tr style="background:#1a2a4a">' +
'<th align="left" width="286" style="'+TH+'">СЧЁТ ЕЛС</th>' +
'<th align="right" width="286" style="'+TH+'">ОСТАТОК НА ' + elsDate + '</th>' +
'</tr>' +
'<tr style="background:#fff">' +
'<td style="'+TD1+'">ЕЛС 22%</td>' +
'<td style="padding:8px 12px;border-bottom:1px solid #e5e7eb;font-size:18px;font-weight:700;color:#20b2aa;text-align:right">'+els22+'</td>' +
'</tr>' +
'<tr style="background:#f8f9fa">' +
'<td style="'+TD1+'">ЕЛС 0%</td>' +
'<td style="padding:8px 12px;font-size:18px;font-weight:700;color:#1a2a4a;text-align:right">'+els0+'</td>' +
'</tr>' +
'</table>' +
'</td></tr>' +

'<tr><td style="padding:8px 24px 16px">' +
'<div style="font-size:13px;font-weight:700;color:#1a2a4a;margin-bottom:10px">Топ-10 должников (просрочка)</div>' +
(topDebt.length ? (
'<table width="572" cellpadding="0" cellspacing="0" border="0" style="border-collapse:collapse;border:1px solid #e5e7eb;border-radius:6px">' +
'<tr style="background:#1a2a4a">' +
'<th align="left" width="400" style="'+TH+'">КЛИЕНТ</th>' +
'<th align="right" width="172" style="'+TH+'">ПРОСРОЧКА</th>' +
'</tr>' +
debtRows +
'</table>'
) : '<div style="font-size:13px;color:#6b7280;padding:12px 0">Просроченных долгов нет</div>') +
'<div style="margin-top:8px;font-size:11px;color:#9ca3af">Всего клиентов с просрочкой: ' + Object.keys(clientMap).length + '</div>' +
'</td></tr>' +

'</table></td></tr></table>' +
'</body></html>';

return [{ json: { today, els0, els22, elsDate, emailHtml, debtCount: Object.keys(clientMap).length } }];
